var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"학……! 하악……! 하아……!","JPN":"はっ……！　はあっ……！　はあ……！","ENG":"Haa....! Haah...! Haaah...!","TWN":"呼……！呼呼……！呼呼……！"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"따돌렸나? 한창 싸우고 있었으니까 여기까지는 못 쫓아오겠지?","JPN":"うまく撒いた？　戦ってる最中だったからここまでは追ってこられないよね？","ENG":"Did I lose them? They were in the middle of fighting, so they couldn’t have chased me all this way, right?","TWN":"甩掉他們了嗎？打得那麼激烈，應該不會追到這裡來吧？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"꺄악?!","JPN":"きゃっ！？","ENG":"Kyaak?!","TWN":"唔？！"},"stage":{"bg":"UNDER","slots":{"L":null,"C":null,"R":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_NPC_TEMPLE_NULL","text":{"KOREA":"잡았습니다, 사제님.","JPN":"捕らえました、司祭様。","ENG":"We have captured her, Your Grace.","TWN":"抓到人了，祭司大人。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"좋아요. 발악하지 못하게 결박해 두세요.","JPN":"結構です。暴れないように縛っておきなさい。","ENG":"Good work. Tie her up so that she can’t run away.","TWN":"很好，把人綁起來，別讓她逃了。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"그, 그 애한테 정신 팔려 있던 거 아니었어?! 어떻게 여기까지……?!","JPN":"あ、あの子に気を取られていたんじゃなかったの！？　どうやってここまで……！？","ENG":"W-weren’t you busy with the other guy?! How did you track me to here...?!","TWN":"你…你們不是忙著對付他嗎？！怎麼會追到這裡來……？！"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"지팡이를 받을 때 만약을 대비해 당신에게 추적 마법을 걸어 뒀어요.","JPN":"杖を受け取るとき、もしもの際に備えてあなたに追跡魔法をかけておきました。","ENG":"When I received the staff, I placed a tracking spell on you just in case.","TWN":"以防萬一，在我拿到杖時，就對你下了追蹤魔法。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"하지만 설마 자기 편을 버리고 도망치다니…… 과연 천한 노예로군요.","JPN":"でもまさか味方を見捨てて逃げるなんて……さすがは卑しい奴隷ですね。","ENG":"But I never expected you to abandon your ally and run... You really are a lowly slave.","TWN":"不過我沒想到你會扔下夥伴逃跑……果然是卑賤的奴隸。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"죽기 전에 사과할 기회는 드리죠. 다른 기사들이 그 소년도 곧 데리고 올 겁니다.","JPN":"死ぬ前に謝る機会を与えてあげましょう。他の騎士がすぐあの少年も連れてくるでしょう。","ENG":"I will give you a chance to apologize to him before you die. The other knights will be bringing the boy here soon.","TWN":"我給你個在死前道歉的機會吧，其他騎士很快就會把他帶過來。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"……누가 사과 따위를 한다고 그래?","JPN":"……誰が謝るって言うの？","ENG":"...Who said that I will be apologizing?","TWN":"……誰要跟他道歉？"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"멍청하게 은전 몇 푼 받을지도 모른다는 말에 혹해서 따라온 게 잘못 아냐?","JPN":"バカみたく小銭に惑わされてついてきた人が悪いんでしょ？","ENG":"Isn’t it his fault for stupidly following me over the promise of a few coins?","TWN":"要怪就怪他自己財迷心竅，說要賞他一點銀子，就傻傻地跟到這裡來！"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"어차피 세상에 믿을 사람은 아무도 없어. 나 자신 말고는.","JPN":"どうせこの世界に信じられる人は誰もいない。自分以外には。","ENG":"After all, you can’t trust anybody in this world. Only yourself.","TWN":"在這個世界上沒有一個人是可以相信的！除了自己以外！"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"호오. 천한 노예 주제에 세상의 진실을 알고 있구나.","JPN":"ほお。卑しい奴隷の分際で世界の真実を知っているとはね。","ENG":"Oh? For a lowly slave, you understand the truth about this world.","TWN":"呵呵，不過是一個卑賤的奴隸，倒是看得很透澈嘛。"},"stage":{"bg":"UNDER","slots":{"L":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRIESTESS_NPC_WEST_NULL","text":{"KOREA":"이 목소리는…… 남쪽 신전의 신전장?","JPN":"この声は……南方の神殿の神殿長？","ENG":"This voice... Head Priestess of the Southern Temple?","TWN":"這個聲音是……南方神殿的祭司長？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_WEST_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_TEMPLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PRIESTESS_NPC_SOUTH_NULL","text":{"KOREA":"같은 성녀 후보로서 통탄할 노릇이야.","JPN":"同じ聖女候補として嘆かわしいことね。","ENG":"As a fellow candidate for the Sainthood, what a deplorable sight this is.","TWN":"同樣身為聖女候選人，我都替你感到難過。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"PRIESTESS_NPC_SOUTH_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};